//-----------------------------------		XExamDefTimeUnits    -----------------------------------------------
function XExamDefTimeUnits() {}
XExamDefTimeUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/xExamDefTimeUnits";
XExamDefTimeUnits.tabIndex = __tabIdx++;
XExamDefTimeUnits.helpText = "Select unit time";
XExamDefTimeUnits.mandatoryOn = [XExamDefTime.dataBinding];
XExamDefTimeUnits.isMandatory = function()
{	var val = Services.getValue(XExamDefTime.dataBinding);
	return( null != val && "" != val );
}	
XExamDefTimeUnits.isTemporary = function(){  return true; }
XExamDefTimeUnits.enableOn = [XExamDefTime.dataBinding];
XExamDefTimeUnits.isEnabled = function(){ return XExamDefTime.isEnabled();}		
XExamDefTimeUnits.logicOn = [SelectItemLsA.dataBinding];
XExamDefTimeUnits.logic = function()
{	if('STA'!=Services.getValue(SelectItemLsA.dataBinding))
	Services.setValue(XExamDefTimeUnits.dataBinding,"");			
}
